<template>
  <v-container>
    <v-row justify="center">
      <v-col cols="12" sm="8" md="6">
        <v-card>
          <v-card-title>Select a Category</v-card-title>
          <v-card-text>
            <!-- Dynamically render dropdowns -->
            <div v-for="(dropdown, index) in dropdowns" :key="dropdown.label + index" class="mt-4">
              <v-select
                v-model="dropdown.selected"
                :items="dropdown.options"
                item-title="name"
                item-value="id"
                :label="dropdown.label"
                @update:modelValue="(value) => handleSelection(value, index)"
              ></v-select>
            </div>
            <!-- Proceed button -->
            <v-btn
              :disabled="!isSelectionComplete"
              color="primary"
              @click="proceedToTemplateSelection"
              class="mt-4"
            >
              Proceed to Template Selection
            </v-btn>
          </v-card-text>
        </v-card>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import axios from 'axios';
import { ref, computed, onMounted } from 'vue';
import { useRouter } from 'vue-router';
import { useStore } from 'vuex';

export default {
  setup() {
    const dropdowns = ref([]);
    const router = useRouter();
    const store = useStore(); // Access the Vuex store instance

    // Fetch root categories on mount
    const fetchRootCategories = async () => {
      try {
        const response = await axios.get('/api/folders/query-folders', {
          params: {
            type: 'category',
            parent: null,
          },
        });

        console.log('Fetched root categories:', response.data);

        dropdowns.value.push({
          label: 'Select a Category',
          options: response.data.map(folder => ({
            id: folder._id,
            name: folder.name,
            path: folder.path,
          })),
          selected: null,
        });
      } catch (error) {
        console.error('Error fetching root categories:', error);
      }
    };

    // Fetch child folders when a dropdown selection is made
    const fetchChildFolders = async (parentId, index) => {
      try {
        const response = await axios.get('/api/folders/query-folders', {
          params: {
            parent: parentId,
            excludeType: 'storage',
          },
        });

        console.log(`Fetched child folders for parent ID ${parentId}:`, response.data);

        const childFolders = response.data;

        // Remove dropdowns deeper than the current selection
        dropdowns.value.splice(index + 1);

        if (childFolders.length > 0) {
          const nextType = childFolders[0].type === 'subcategory' ? 'Subcategory' : 'Category';

          dropdowns.value.push({
            label: `Select a ${nextType}`,
            options: childFolders.map(folder => ({
              id: folder._id,
              name: folder.name,
              path: folder.path,
            })),
            selected: null,
          });
        }
      } catch (error) {
        console.error('Error fetching child folders:', error);
      }
    };

    const handleSelection = (selectedId, index) => {
      if (!selectedId) return;
      fetchChildFolders(selectedId, index);
    };

    const isSelectionComplete = computed(() => {
      return dropdowns.value.length > 0 && dropdowns.value[dropdowns.value.length - 1].selected;
    });

    const proceedToTemplateSelection = () => {
      const hierarchy = dropdowns.value.map(dropdown => {
        const selectedOption = dropdown.options.find(option => option.id === dropdown.selected);
        return {
          id: dropdown.selected,
          name: selectedOption?.name,
          path: selectedOption?.path,
        };
      });

      console.log('Constructed hierarchy with paths:', hierarchy);

      router.push({ name: 'userOptionsPage', query: { hierarchy: JSON.stringify(hierarchy) } });
    };

    // Reset Vuex store on component mount
    onMounted(() => {
      store.dispatch('resetStore'); // Dispatch the resetStore action
      fetchRootCategories(); // Fetch root categories after reset
    });

    return {
      dropdowns,
      handleSelection,
      isSelectionComplete,
      proceedToTemplateSelection,
    };
  },
};
</script>
